  const updatePage = (updates: Partial<LovePage>) => {
    setPageData(prev => ({ ...prev, ...updates }));
  };

  const checkAccess = (featureId: string, itemIsPro: boolean, adCount: number = 1) => {
    if (isPro) return true;
    if (!itemIsPro) return true;
    const expiry = pageData.adUnlocks?.[featureId];
    if (expiry && expiry > Date.now()) return true;

    setMonetizationModal({ 
      open: true, 
      featureId, 
      type: adCount > 0 ? 'both' : 'pro', 
      adCountNeeded: adCount 
    });
    return false;
  };

  const handleWatchAd = (featureId: string) => {
    setAiLoading(true);
    setTimeout(() => {
      const expiry = Date.now() + (24 * 60 * 60 * 1000);
      updatePage({
        adUnlocks: {
          ...(pageData.adUnlocks || {}),
          [featureId]: expiry
        }
      });
      setMonetizationModal({ ...monetizationModal, open: false });
      setAiLoading(false);
    }, 2000);
  };

  const handleSuggestTitle = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_title', type: 'pro' });
      return;
    }
    setAiLoading(true);
    const results = await getTitleSuggestions(pageData.day, pageData.message);
    setTitleSuggestions(results);
    setAiLoading(false);
  };

  const handleAIPolish = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_polish', type: 'pro' });
      return;
    }
    if (!pageData.message) return;
    setAiLoading(true);
    const polished = await getAIPolish(pageData.message);
    updatePage({ message: polished });
    setAiLoading(false);
  };

  const fetchSuggestions = async (mood: string) => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_helper', type: 'pro' });
      return;
    }
    setSelectedMood(mood);
    setAiLoading(true);
    const results = await getMessageSuggestions(mood, isPro);
    setSuggestions(results);
    setAiLoading(false);
  };

  const addTimelineEvent = () => {
    const freeLimit = 3;
    const currentCount = pageData.timeline.length;
    if (!isPro && currentCount >= freeLimit) {
      const unlockKey = `timeline_extra_${currentCount + 1}`;
      if (!checkAccess(unlockKey, true, 1)) return;
    }
    const newEvent: TimelineEvent = {
      id: Math.random().toString(36).substr(2, 5),
      date: new Date().toLocaleDateString(),
      title: 'A Beautiful Moment',
      description: 'Describe this special memory...'
    };
    updatePage({ timeline: [...pageData.timeline, newEvent] });
  };

  const handlePhotoUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newTimeline = [...pageData.timeline];
        newTimeline[index].photoUrl = reader.result as string;
        updatePage({ timeline: newTimeline });
      };
      reader.readAsDataURL(file);
    }
  };

  const toggleEffect = (id: string, itemIsPro: boolean) => {
    if (!checkAccess(`effect_${id}`, itemIsPro, 1)) return;
    const isAlreadyAdded = pageData.effects.includes(id);
    if (isAlreadyAdded) {
      updatePage({ effects: pageData.effects.filter(e => e !== id) });
    } else {
      let newEffects = [...pageData.effects, id];
      if (newEffects.length > 3) newEffects.shift();
      updatePage({ effects: newEffects });
