                        className={`relative p-6 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-4 ${pageData.templateId === t.id ? 'border-pink-400 bg-pink-50 shadow-romantic scale-[1.05]' : 'border-gray-50 bg-white text-gray-400 hover:border-pink-100'}`}
