          >
            <motion.div 
              initial={{ scale: 0.9, y: 30 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 30 }}
              className="bg-white rounded-[4rem] p-14 max-w-lg w-full text-center shadow-2xl border border-pink-50 relative overflow-hidden"
            >
              <div className="absolute -top-10 -right-10 w-40 h-40 bg-pink-50 rounded-full blur-3xl opacity-50" />
              <div className="w-24 h-24 bg-pink-50 rounded-[2.5rem] flex items-center justify-center text-pink-400 mx-auto mb-8 shadow-inner">
                <Lock className="w-10 h-10" />
              </div>
              <h3 className="text-4xl font-bold text-gray-800 mb-4 font-quicksand">Premium Touch Required ✨</h3>
              <p className="text-gray-500 mb-12 leading-relaxed font-medium text-lg">This artistic feature is curated for our PRO creators, but you can unlock a 24-hour window by watching a romantic spotlight.</p>

              <div className="space-y-4">
                {monetizationModal.type !== 'pro' && (
                  <button 
                    onClick={() => handleWatchAd(monetizationModal.featureId)}
                    className="w-full py-6 bg-pink-500 text-white rounded-[2rem] font-bold text-xl flex items-center justify-center gap-4 shadow-romantic hover:bg-pink-600 transition-all"
