                    <Play className="w-6 h-6 fill-current" />
                    <span>Watch {monetizationModal.adCountNeeded} Spotlight</span>
                  </button>
                )}
                <button 
                  onClick={() => { onUpgrade(); setMonetizationModal({ ...monetizationModal, open: false }); }}
                  className="w-full py-6 bg-white border-2 border-pink-100 text-pink-500 rounded-[2rem] font-bold text-xl hover:bg-pink-50 transition-all"
                >
                  Join Valentine PRO
                </button>
                <button 
                  onClick={() => setMonetizationModal({ ...monetizationModal, open: false })}
                  className="text-gray-400 font-bold hover:text-gray-600 transition-colors pt-6 text-xs uppercase tracking-widest"
                >
                  Maybe next time
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

