} from 'lucide-react';
import { LovePage } from '../types';

interface PreviewProps {
  page: LovePage;
  onBack?: () => void;
  isPro: boolean;
}

const Preview: React.FC<PreviewProps> = ({ page, onBack, isPro }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLines, setRevealedLines] = useState<string[]>([]);
  const [unlocked, setUnlocked] = useState(!page.isSecret);
  const [isFinished, setIsFinished] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const lines = page.message.split('\n').filter(l => l.trim() !== '');

  useEffect(() => {
    if (showContent && unlocked) {
      let currentLine = 0;
      const interval = setInterval(() => {
        if (currentLine < lines.length) {
          setRevealedLines(prev => [...prev, lines[currentLine]]);
          currentLine++;
          window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
        } else {
          clearInterval(interval);
          setTimeout(() => {
            setIsFinished(true);
            window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
          }, 1200);
        }
      }, 2000); // Cinematic, slower reading pace
      return () => clearInterval(interval);
    }
  }, [showContent, unlocked, lines.length]);

  const handleShare = async () => {
    const url = window.location.href;
    if (navigator.share) {
      try {
        await navigator.share({
          title: page.title,
          text: `Check out this special ${page.day} message for you!`,
          url: url,
        });
      } catch (err) {
        setShowShareModal(true);
      }
    } else {
      setShowShareModal(true);
    }
  };

  const getTemplateStyles = () => {
    switch (page.templateId) {
      case 'p1': return "bg-gradient-to-br from-[#1a1a1a] to-[#2d1b1b] text-rose-200 font-serif shadow-2xl ring-1 ring-white/10"; 
      case 'p2': return "bg-[#0a0e1a] text-blue-100 font-light tracking-[0.1em] overflow-hidden"; 
      case 'p3': return "bg-[#fffdfb] border-[40px] border-[#fde2e4] font-quicksand text-rose-800"; 
      case 'p4': return "bg-black text-white font-mono tracking-tighter uppercase"; 
      case 'p5': return "bg-[#fdfcf0] text-[#5d4037] font-serif italic selection:bg-rose-100"; 
      case 't1': return "bg-[#fff5f5] text-gray-700 font-nunito"; 
