interface PreviewProps {
  page: LovePage;
  onBack?: () => void;
  isPro: boolean;
}

const Preview: React.FC<PreviewProps> = ({ page, onBack, isPro }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLines, setRevealedLines] = useState<string[]>([]);
  const [unlocked, setUnlocked] = useState(!page.isSecret);
  const [isFinished, setIsFinished] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const lines = useMemo(() => page.message.split('\n').filter(l => l.trim() !== ''), [page.message]);

  useEffect(() => {
    if (showContent && unlocked) {
      let currentLine = 0;
      const interval = setInterval(() => {
        if (currentLine < lines.length) {
          setRevealedLines(prev => [...prev, lines[currentLine]]);
          currentLine++;
          window.scrollTo({ 
            top: document.body.scrollHeight, 
            behavior: 'smooth' 
          });
        } else {
          clearInterval(interval);
          setTimeout(() => {
            setIsFinished(true);
            window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
          }, 1500);
        }
      }, 2800); 
      return () => clearInterval(interval);
    }
  }, [showContent, unlocked, lines]);

  const copyToClipboard = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: page.title,
          text: `A cinematic love letter for you: ${page.title}`,
          url: window.location.href,
        });
      } catch (err) {
        setShowShareModal(true);
      }
    } else {
      setShowShareModal(true);
    }
  };

  const getTemplateStyles = () => {
    switch (page.templateId) {
      case 'p1': return "bg-gradient-to-br from-[#0f0c29] via-[#302b63] to-[#24243e] text-rose-100 font-serif"; 
      case 'p2': return "bg-[#000428] bg-gradient-to-b from-[#000428] to-[#004e92] text-blue-50 font-light tracking-[0.15em]"; 
      case 'p3': return "bg-[#fffafa] border-[30px] md:border-[80px] border-[#ffe4e1] font-quicksand text-rose-900"; 
      case 'p4': return "bg-[#050505] text-[#f8f8f8] font-mono uppercase tracking-tighter"; 
      case 'p5': return "bg-[#fcf8e8] text-[#4a3728] font-serif italic selection:bg-pink-100"; 
      case 't1': return "bg-[#fff5f5] text-gray-700 font-nunito"; 
      default: return "bg-[#FFFDF9] text-gray-800 font-nunito";
    }
  };

  const renderEffect = (effectId: string) => {
    // Standardizing IDs for a cleaner switch
