                animate={{ 
                  y: "120vh", 
                  rotate: 360, 
                  x: `${Math.random() * 100 - 10}%` 
                }}
                transition={{ 
                  duration: 18 + Math.random() * 12, 
                  repeat: Infinity, 
                  delay: i * 0.7,
                  ease: "linear"
                }}
              >🌸</motion.div>
            ))}
          </div>
        );
      case 'e7': 
        return (
          <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
            {Array.from({ length: 30 }).map((_, i) => (
              <motion.div
                key={i}
                className="absolute text-rose-500/15 text-2xl"
                initial={{ y: -80, x: `${Math.random() * 100}%` }}
                animate={{ y: "120vh", scale: [1, 1.2, 1] }}
                transition={{ 
                  duration: 9 + Math.random() * 5, 
                  repeat: Infinity, 
                  delay: i * 0.4,
                  ease: "easeIn"
                }}
              >❤️</motion.div>
            ))}
          </div>
        );
      case 'p2': 
      case 'e6':
        return (
          <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
            {Array.from({ length: 80 }).map((_, i) => (
              <motion.div
                key={i}
