import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, 
  Sparkles, 
  Image as ImageIcon, 
  Plus, 
  Eye, 
  Send,
  Wand2,
  Trash2,
  Lock,
  ChevronRight,
  Camera,
  Play,
  CheckCircle2,
  Clock,
  Star,
  Quote,
  // Added missing Heart icon
  Heart
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { TEMPLATES, EFFECTS, GIF_IDS } from '../constants';
import { getAIPolish, getMessageSuggestions, getTitleSuggestions } from '../services/geminiService';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [step, setStep] = useState(1);
  const [pageData, setPageData] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: `My Special ${initialDay}`,
    message: '',
    isSecret: false,
    templateId: 't1',
    effects: [],
    timeline: [],
    isPublished: false,
    adUnlocks: {}
  });

  const [aiLoading, setAiLoading] = useState(false);
  const [helperOpen, setHelperOpen] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [titleSuggestions, setTitleSuggestions] = useState<string[]>([]);
  const [selectedMood, setSelectedMood] = useState<string | null>(null);
  const [previewGif, setPreviewGif] = useState<string | null>(null);

  const [monetizationModal, setMonetizationModal] = useState<{ 
    open: boolean; 
    featureId: string; 
    type: 'ad' | 'pro' | 'both'; 
    adCountNeeded?: number 
  }>({ open: false, featureId: '', type: 'pro' });

  const updatePage = (updates: Partial<LovePage>) => {
    setPageData(prev => ({ ...prev, ...updates }));
  };

  const checkAccess = (featureId: string, itemIsPro: boolean, adCount: number = 1) => {
    if (isPro) return true;
    if (!itemIsPro) return true;
    const expiry = pageData.adUnlocks?.[featureId];
    if (expiry && expiry > Date.now()) return true;

    setMonetizationModal({ 
      open: true, 
      featureId, 
      type: adCount > 0 ? 'both' : 'pro', 
      adCountNeeded: adCount 
    });
    return false;
  };

  const handleWatchAd = (featureId: string) => {
    setAiLoading(true);
    setTimeout(() => {
      const expiry = Date.now() + (24 * 60 * 60 * 1000);
      updatePage({
        adUnlocks: {
          ...(pageData.adUnlocks || {}),
          [featureId]: expiry
        }
      });
      setMonetizationModal({ ...monetizationModal, open: false });
      setAiLoading(false);
    }, 2500);
  };

  const handleSuggestTitle = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_title', type: 'pro' });
      return;
    }
    setAiLoading(true);
    const results = await getTitleSuggestions(pageData.day, pageData.message);
    setTitleSuggestions(results);
    setAiLoading(false);
  };

  const handleAIPolish = async () => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_polish', type: 'pro' });
      return;
    }
    if (!pageData.message) return;
    setAiLoading(true);
    const polished = await getAIPolish(pageData.message);
    updatePage({ message: polished });
    setAiLoading(false);
  };

  const fetchSuggestions = async (mood: string) => {
    if (!isPro) {
      setMonetizationModal({ open: true, featureId: 'ai_helper', type: 'pro' });
      return;
    }
    setSelectedMood(mood);
    setAiLoading(true);
    const results = await getMessageSuggestions(mood, isPro);
    setSuggestions(results);
    setAiLoading(false);
  };

  const addTimelineEvent = () => {
    const freeLimit = 3;
    const currentCount = pageData.timeline.length;
    if (!isPro && currentCount >= freeLimit) {
      const unlockKey = `timeline_extra_${currentCount + 1}`;
      if (!checkAccess(unlockKey, true, 1)) return;
    }
    const newEvent: TimelineEvent = {
      id: Math.random().toString(36).substr(2, 5),
      date: new Date().toLocaleDateString(),
      title: 'A Beautiful Moment',
      description: 'Describe this special memory...'
    };
    updatePage({ timeline: [...pageData.timeline, newEvent] });
  };

  const handlePhotoUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newTimeline = [...pageData.timeline];
        newTimeline[index].photoUrl = reader.result as string;
        updatePage({ timeline: newTimeline });
      };
      reader.readAsDataURL(file);
    }
  };

  const toggleEffect = (id: string, itemIsPro: boolean) => {
    if (!checkAccess(`effect_${id}`, itemIsPro, 1)) return;
    const isAlreadyAdded = pageData.effects.includes(id);
    if (isAlreadyAdded) {
      updatePage({ effects: pageData.effects.filter(e => e !== id) });
    } else {
      let newEffects = [...pageData.effects, id];
      if (newEffects.length > 3) newEffects.shift();
      updatePage({ effects: newEffects });
    }
  };

  const steps = [
    { name: "Vision", desc: "Setting the narrative tone" },
    { name: "Heartfelt Letter", desc: "Pouring your soul into words" },
    { name: "Memory Chapters", desc: "Mapping your unique journey" },
    { name: "Cinematography", desc: "Designing the atmospheric feel" },
    { name: "Seal & Deliver", desc: "Finalizing your masterpiece" }
  ];

  const moods = [
    { id: 'cute', label: 'Playful', color: 'bg-orange-50 text-orange-600' },
    { id: 'romantic', label: 'Classic', color: 'bg-pink-50 text-pink-600' },
    { id: 'emotional', label: 'Soulful', color: 'bg-blue-50 text-blue-600' },
    { id: 'deep', label: 'Poetic', color: 'bg-purple-50 text-purple-600' }
  ];

  return (
    <div className="pt-32 pb-40 px-6 max-w-6xl mx-auto z-10 relative">
      <motion.button 
        initial={{ opacity: 0, x: -15 }}
        animate={{ opacity: 1, x: 0 }}
        onClick={onBack}
        className="mb-10 flex items-center gap-3 text-gray-400 hover:text-pink-500 transition-all font-bold tracking-[0.4em] text-[10px] uppercase"
      >
        <ArrowLeft className="w-5 h-5" />
        <span>Exit Sanctuary</span>
      </motion.button>

      <div className="bg-white rounded-[4.5rem] shadow-romantic border border-pink-50/50 p-12 md:p-20 relative overflow-hidden">
        {/* Legendary AI Loader */}
        <AnimatePresence>
          {aiLoading && (
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="absolute inset-0 z-[100] glass-premium flex flex-col items-center justify-center gap-8"
            >
              <div className="relative">
                <motion.div 
                  animate={{ scale: [1, 1.4, 1], rotate: [0, 360] }}
                  transition={{ duration: 4, repeat: Infinity, ease: "linear" }}
                  className="w-24 h-24 border-t-4 border-pink-400 border-r-4 border-pink-100 rounded-full"
                />
                <motion.div 
                  animate={{ scale: [0.8, 1.2, 0.8] }}
                  transition={{ duration: 2, repeat: Infinity }}
                  className="absolute inset-0 flex items-center justify-center text-pink-400"
                >
                  <Sparkles className="w-10 h-10" />
                </motion.div>
              </div>
              <p className="font-bold text-pink-500 tracking-[0.6em] uppercase text-xs animate-pulse">Designing with Soul...</p>
            </motion.div>
          )}
