import { AnimatePresence } from 'framer-motion';

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, Sparkles, Plus, Wand2, Trash2, Lock, 
  Camera, Mic, MicOff, Clock
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { setupLiveSession, decodeAudio, decodeAudioData, encodeAudio } from '../services/liveService';
import { getAIPolish, getTitleSuggestions } from '../services/geminiService';
import { TEMPLATES, EFFECTS, VALENTINE_DAYS } from '../constants';
import VoiceAura from './VoiceAura';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

// Builder component for creating Valentine pages with AI and Live Voice assistance.
const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [page, setPage] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: '',
    message: '',
    isSecret: false,
    templateId: 't1',
    effects: [],
    timeline: [],
    isPublished: false,
    publishedAt: 0,
    lastEdited: Date.now()
  });

  const [isLiveActive, setIsLiveActive] = useState(false);
  const [isModelSpeaking, setIsModelSpeaking] = useState(false);
  const [isAILoading, setIsAILoading] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    return () => {
      stopLiveSession();
    };
  }, []);

  const stopLiveSession = () => {
    setIsLiveActive(false);
    setIsModelSpeaking(false);
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    if (outputContextRef.current) {
      outputContextRef.current.close();
      outputContextRef.current = null;
    }
  };

  const startLiveSession = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const callbacks = {
        onopen: () => {
          const source = audioContextRef.current!.createMediaStreamSource(stream);
          const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const base64 = encodeAudio(inputData);
            sessionPromiseRef.current?.then((session) => {
              session.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(audioContextRef.current!.destination);
        },
        onmessage: async (message: any) => {
          // Process model audio output for real-time conversation.
          const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (audioData) {
            setIsModelSpeaking(true);
            const ctx = outputContextRef.current!;
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
            const buffer = await decodeAudioData(decodeAudio(audioData), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(ctx.destination);
            source.onended = () => {
              sourcesRef.current.delete(source);
              if (sourcesRef.current.size === 0) setIsModelSpeaking(false);
            };
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
          }

          if (message.serverContent?.interrupted) {
            sourcesRef.current.forEach(s => {
              try { s.stop(); } catch (e) {}
            });
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
            setIsModelSpeaking(false);
          }

          // Handle function calls to update the draft based on conversation.
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              let result = { status: "success" };
              if (fc.name === "updateBasicInfo") {
                setPage(prev => ({ ...prev, ...fc.args }));
              } else if (fc.name === "addTimelineMilestone") {
                const newEvent: TimelineEvent = {
                  id: Math.random().toString(36).substr(2, 9),
                  date: fc.args.date || new Date().toLocaleDateString(),
                  title: fc.args.title,
                  description: fc.args.description
                };
                setPage(prev => ({ ...prev, timeline: [...prev.timeline, newEvent] }));
              }

              sessionPromiseRef.current?.then(session => {
                session.sendToolResponse({
                  functionResponses: [{
                    id: fc.id,
                    name: fc.name,
                    response: { result }
                  }]
                });
              });
            }
          }
        },
        onerror: (e: any) => console.error("Live Error", e),
        onclose: () => setIsLiveActive(false)
      };

      sessionPromiseRef.current = setupLiveSession(callbacks);
      setIsLiveActive(true);
    } catch (err) {
      console.error("Failed to start live session", err);
    }
  };

  const handlePolish = async () => {
    if (!page.message) return;
    setIsAILoading(true);
    const polished = await getAIPolish(page.message);
    setPage(prev => ({ ...prev, message: polished }));
    setIsAILoading(false);
  };

  const addMilestone = () => {
    const newEvent: TimelineEvent = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
      title: 'New Memory',
      description: 'Describe this precious moment...'
    };
    setPage(prev => ({ ...prev, timeline: [...prev.timeline, newEvent] }));
  };

  return (
    <div className="min-h-screen bg-[#FFFDF9] pt-32 pb-48 px-6">
      <div className="max-w-4xl mx-auto space-y-12">
        {/* Navigation and Controls */}
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="p-4 hover:bg-pink-50 rounded-2xl transition-colors">
            <ArrowLeft className="w-6 h-6 text-gray-400" />
          </button>
          <div className="flex items-center gap-4">
             <button 
               onClick={() => isLiveActive ? stopLiveSession() : startLiveSession()}
               className={`flex items-center gap-3 px-6 py-3 rounded-full font-bold text-sm transition-all ${isLiveActive ? 'bg-rose-500 text-white shadow-lg' : 'bg-pink-100 text-pink-500'}`}
             >
               {isLiveActive ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
               <span>{isLiveActive ? 'End Voice Guide' : 'AI Voice Help'}</span>
             </button>
             <button 
               onClick={() => onPublish(page)}
               className="px-8 py-3 bg-pink-500 text-white rounded-full font-bold shadow-romantic hover:bg-pink-600 transition-all"
             >
               Publish Page
             </button>
          </div>
        </div>

        {/* Core Content Form */}
        <div className="glass-premium p-10 rounded-[3rem] border border-pink-50 space-y-10 shadow-xl">
          <div className="space-y-4">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Choose the Occasion</label>
            <div className="flex flex-wrap gap-3">
              {VALENTINE_DAYS.map(d => (
                <button
                  key={d.name}
                  onClick={() => setPage(prev => ({ ...prev, day: d.name }))}
                  className={`px-6 py-2 rounded-full text-xs font-bold border transition-all ${page.day === d.name ? 'bg-pink-400 border-pink-400 text-white shadow-md' : 'border-pink-100 text-pink-300 hover:border-pink-200'}`}
                >
                  {d.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Heartfelt Title</label>
              <button 
                onClick={async () => {
                  const suggestions = await getTitleSuggestions(page.day, page.message);
                  if (suggestions.length) setPage(prev => ({ ...prev, title: suggestions[0] }));
                }}
                className="text-[10px] font-bold text-pink-400 hover:text-pink-600 flex items-center gap-1"
              >
                <Sparkles className="w-3 h-3" /> AI Suggest
              </button>
            </div>
            <input 
              value={page.title}
              onChange={e => setPage(prev => ({ ...prev, title: e.target.value }))}
              placeholder="e.g., To My Forever Valentine"
              className="w-full bg-transparent border-b-2 border-pink-100 p-4 text-3xl font-bold font-quicksand focus:outline-none focus:border-pink-400 transition-colors"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Love Letter</label>
              <button 
                onClick={handlePolish}
                disabled={isAILoading}
                className="flex items-center gap-2 px-4 py-2 bg-pink-50 text-pink-500 rounded-xl text-xs font-bold hover:bg-pink-100 transition-all disabled:opacity-50"
              >
                {isAILoading ? <Clock className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                AI Polish
              </button>
            </div>
            <textarea 
              value={page.message}
              onChange={e => setPage(prev => ({ ...prev, message: e.target.value }))}
              placeholder="Write your feelings here..."
              rows={6}
              className="w-full bg-pink-50/30 rounded-3xl p-6 font-romantic text-xl italic border border-transparent focus:border-pink-100 focus:outline-none transition-all resize-none shadow-inner"
            />
          </div>
        </div>

        {/* Timeline Builder */}
        <div className="space-y-8">
           <div className="flex items-center justify-between">
             <h3 className="text-2xl font-bold text-gray-800 font-quicksand">Our Chapters</h3>
             <button 
               onClick={addMilestone}
               className="flex items-center gap-2 px-5 py-2.5 bg-white border border-pink-100 text-pink-500 rounded-full text-xs font-bold shadow-sm hover:shadow-md transition-all"
             >
               <Plus className="w-4 h-4" /> Add Memory
             </button>
           </div>

           <div className="grid gap-6">
             {page.timeline.map((event, idx) => (
               <motion.div 
                 key={event.id}
                 layout
                 initial={{ opacity: 0, x: -20 }}
                 animate={{ opacity: 1, x: 0 }}
                 className="bg-white p-8 rounded-[2.5rem] border border-pink-50 shadow-sm relative group"
               >
                 <button 
                   onClick={() => setPage(prev => ({ ...prev, timeline: prev.timeline.filter(t => t.id !== event.id) }))}
                   className="absolute top-6 right-6 p-2 text-gray-200 hover:text-rose-400 transition-colors opacity-0 group-hover:opacity-100"
                 >
                   <Trash2 className="w-4 h-4" />
                 </button>
                 <div className="flex flex-col md:flex-row gap-8">
                   <div className="w-full md:w-32 h-32 bg-pink-50 rounded-2xl flex flex-col items-center justify-center text-pink-200 cursor-pointer hover:bg-pink-100 transition-colors border-2 border-dashed border-pink-100">
                     <Camera className="w-6 h-6 mb-1" />
                     <span className="text-[10px] font-bold">Add Photo</span>
                   </div>
                   <div className="flex-1 space-y-4">
                      <input 
                        value={event.date}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].date = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        className="text-[10px] font-bold uppercase tracking-[0.4em] text-pink-300 focus:outline-none bg-transparent"
                      />
                      <input 
                        value={event.title}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].title = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        className="w-full text-xl font-bold text-gray-800 font-quicksand focus:outline-none bg-transparent"
                        placeholder="Memory Title"
                      />
                      <textarea 
                        value={event.description}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].description = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        className="w-full text-sm text-gray-500 font-medium focus:outline-none resize-none bg-transparent"
                        placeholder="Describe this moment..."
                        rows={2}
                      />
                   </div>
                 </div>
               </motion.div>
             ))}
           </div>
        </div>

        {/* Style Selection */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          <div className="space-y-6">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Cinematic Template</label>
            <div className="grid grid-cols-2 gap-4">
               {TEMPLATES.map(t => (
                 <button
                   key={t.id}
                   onClick={() => (!t.isPro || isPro) ? setPage(prev => ({ ...prev, templateId: t.id })) : onUpgrade()}
                   className={`p-6 rounded-[2rem] border-2 text-left transition-all ${page.templateId === t.id ? 'border-pink-400 bg-pink-50/50' : 'border-pink-50 hover:border-pink-100'}`}
                 >
                   <div className="flex items-center justify-between mb-2">
                     <span className="font-bold text-sm text-gray-800">{t.name}</span>
                     {t.isPro && <Lock className="w-3 h-3 text-pink-300" />}
                   </div>
                   <div className="w-full h-1 bg-pink-200/20 rounded-full" />
                 </button>
               ))}
            </div>
          </div>

          <div className="space-y-6">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Magic Effects</label>
            <div className="flex flex-wrap gap-3">
               {EFFECTS.map(e => (
                 <button
                   key={e.id}
                   onClick={() => {
                    if (e.isPro && !isPro) return onUpgrade();
                    setPage(prev => ({
                      ...prev,
                      effects: prev.effects.includes(e.id) 
                        ? prev.effects.filter(id => id !== e.id) 
                        : [...prev.effects, e.id]
                    }));
                   }}
                   className={`px-5 py-2.5 rounded-full text-[10px] font-bold transition-all border ${page.effects.includes(e.id) ? 'bg-pink-400 border-pink-400 text-white' : 'border-pink-100 text-pink-300 hover:border-pink-200'}`}
                 >
                   {e.name}
                   {e.isPro && " 👑"}
                 </button>
               ))}
            </div>
          </div>
        </div>
      </div>

      <VoiceAura isActive={isLiveActive} isModelSpeaking={isModelSpeaking} />
    </div>
  );
};

export default Builder;

